const text = $input.first().json.output;

const cleaned = text
  .replace("```json", "")
  .replace("```", "")
  .trim();

return [
  {
    json: JSON.parse(cleaned)
  }
];

parameters.query:
SELECT *
FROM propiedades
WHERE 1=1
AND (
  '{{ $json.data.tipo_propiedad }}' = ''
  OR tipo_propiedad = '{{ $json.data.tipo_propiedad }}'
)
AND (
  '{{ $json.data.locacion }}' = ''
  OR locacion = '{{ $json.data.locacion }}'
)
AND (
  {{ $json.data.precio_usd || 0 }} = 0
  OR precio_usd <= {{ $json.data.precio_usd || 0 }}
)
AND (
  {{ $json.data.metros_cuadrados || 0 }} = 0
  OR metros_cuadrados >= {{ $json.data.metros_cuadrados || 0 }}
)
AND (
    '{{ $json.data.operacion }}' = ''
    OR '{{ $json.data.operacion }}' IS NULL
    OR operacion = '{{ $json.data.operacion }}'
)
ORDER BY precio_usd ASC
LIMIT 10;

parameters.jsCode:
const propiedades = $input.all();

let mensaje = "🏠 Encontré las siguientes propiedades:\n\n";

for (const item of propiedades) {
  const p = item.json;

  mensaje += `📍 ${p.titulo}\n`;
  mensaje += `🏡 Tipo: ${p.tipo_propiedad}\n`;
  mensaje += `📌 Ubicación: ${p.locacion}\n`;
  mensaje += `📐 ${p.metros_cuadrados} m²\n`;
  mensaje += `💰 USD ${p.precio_usd}\n`;
  mensaje += `📝 ${p.descripcion}\n`;
  mensaje += `🔗 ${p.url}\n\n`;
}

mensaje += "Si te interesa alguna propiedad puedo brindarte más información.";

return [{
  json: {
    body: mensaje
  }
}];

